#[verifier(spinoff_prover)] /* vattr */
proof fn test6(b: u32, b2: u32) {
    assert(b * b2 == b2 * b) by(nonlinear_arith);
    assert(b << 2 == mul(b, 4)) by(bit_vector);
    assert(((b << 2) as int) == (b as int) * 4);  // FAILS
}

